import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { finalize } from 'rxjs';
import { ResumeAnalysis } from '../../../core/models/analysis.model';
import { AiService } from '../../../core/services/ai.service';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-resume-analysis',
  templateUrl: './resume-analysis.component.html'
})
export class ResumeAnalysisComponent implements OnInit {
  resumeId = 0;
  analysis: ResumeAnalysis | null = null;
  loading = true;
  refreshing = false;

  constructor(
    private readonly route: ActivatedRoute,
    private readonly resumeService: ResumeService,
    private readonly aiService: AiService
  ) {
  }

  ngOnInit(): void {
    this.resumeId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadOrAnalyze();
  }

  runImprove(): void {
    this.refreshing = true;
    this.aiService.improveResume(this.resumeId)
      .pipe(finalize(() => (this.refreshing = false)))
      .subscribe((analysis) => {
        this.analysis = analysis;
      });
  }

  private loadOrAnalyze(): void {
    this.resumeService.getResumeAnalysis(this.resumeId).subscribe({
      next: (analysis) => {
        this.analysis = analysis;
        this.loading = false;
      },
      error: () => {
        this.aiService.analyzeResume(this.resumeId).subscribe((analysis) => {
          this.analysis = analysis;
          this.loading = false;
        });
      }
    });
  }
}
<app-loader *ngIf="loading" message="Analyzing your resume"></app-loader>

<div *ngIf="!loading && analysis" class="space-y-6">
  <section class="grid gap-5 xl:grid-cols-[0.85fr_1.15fr]">
    <app-score-card [score]="analysis.atsScore"></app-score-card>

    <div class="shell-card p-6">
      <div class="flex flex-wrap items-start justify-between gap-4">
        <div>
          <p class="eyebrow">AI Analysis</p>
          <h2 class="section-title mt-2 text-4xl text-[#17172b]">Resume insights</h2>
        </div>
        <button class="btn-secondary px-4 py-2 text-sm" (click)="runImprove()" [disabled]="refreshing">
          {{ refreshing ? 'Refreshing...' : 'Improve Again' }}
        </button>
      </div>
      <p class="mt-5 text-base leading-7 text-[#667085]">{{ analysis.summaryFeedback }}</p>
    </div>
  </section>

  <section class="grid gap-5 lg:grid-cols-2">
    <div class="shell-card p-6">
      <p class="text-lg font-bold text-[#16a34a]">Strengths</p>
      <ul class="mt-4 space-y-3 text-sm leading-7 text-[#667085]">
        <li *ngFor="let item of analysis.strengths">{{ item }}</li>
      </ul>
    </div>

    <div class="shell-card p-6">
      <p class="text-lg font-bold text-[#ef4444]">Weaknesses</p>
      <ul class="mt-4 space-y-3 text-sm leading-7 text-[#667085]">
        <li *ngFor="let item of analysis.weaknesses">{{ item }}</li>
      </ul>
    </div>
  </section>

  <section class="grid gap-5 lg:grid-cols-2">
    <div class="shell-card p-6">
      <p class="eyebrow">Missing Keywords</p>
      <div class="mt-5 flex flex-wrap gap-2">
        <span *ngFor="let keyword of analysis.missingKeywords" class="rounded-full bg-[#fff0f0] px-3 py-2 text-sm font-semibold text-[#ef4444]">
          {{ keyword }}
        </span>
      </div>
    </div>

    <div class="shell-card p-6">
      <p class="eyebrow">Extracted Skills</p>
      <div class="mt-5 flex flex-wrap gap-2">
        <span *ngFor="let skill of analysis.extractedSkills" class="rounded-full bg-[#edf2ff] px-3 py-2 text-sm font-semibold text-[#5b5cf0]">
          {{ skill }}
        </span>
      </div>
    </div>
  </section>

  <section class="grid gap-5 xl:grid-cols-[0.9fr_1.1fr]">
    <div class="shell-card p-6">
      <p class="eyebrow">Improved Summary</p>
      <p class="mt-5 text-sm leading-7 text-[#667085]">{{ analysis.improvedSummary }}</p>
    </div>

    <div class="shell-card p-6">
      <p class="eyebrow">Improved Experience Bullets</p>
      <ul class="mt-5 space-y-3 text-sm leading-7 text-[#667085]">
        <li *ngFor="let bullet of analysis.improvedExperienceBullets">• {{ bullet }}</li>
      </ul>
    </div>
  </section>

  <div class="flex gap-3">
    <a [routerLink]="['/resume', resumeId, 'jobs']" class="btn-primary">View Matching Jobs</a>
    <a [routerLink]="['/resume', resumeId]" class="btn-secondary">Back to Resume</a>
  </div>
</div>
